#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int *leftChild, *rightChild;
int *isChild;

int dfs(int node){
    if(node==0) return 0;
    int lh = dfs(leftChild[node]);
    if(lh==-1) return -1;
    int rh = dfs(rightChild[node]);
    if(rh==-1) return -1;
    if(abs(lh-rh)>1) return -1;
    return 1 + (lh>rh?lh:rh);
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        leftChild = (int*)calloc(N+1,sizeof(int));
        rightChild = (int*)calloc(N+1,sizeof(int));
        isChild = (int*)calloc(N+1,sizeof(int));
        for(int i=0;i<N-1;++i){
            int p,c; char dir; scanf("%d %d %c",&p,&c,&dir);
            if(dir=='L') leftChild[p]=c; else rightChild[p]=c;
            isChild[c]=1;
        }
        int root=1; for(int i=1;i<=N;++i) if(!isChild[i]){root=i;break;}
        int res = dfs(root);
        printf("%s\n", res==-1?"NO":"YES");
        free(leftChild); free(rightChild); free(isChild);
    }
    return 0;
}

