#include <bits/stdc++.h>
using namespace std;

int dfs(int node, const vector<int>& left, const vector<int>& right){
    if(node==0) return 0;
    int lh = dfs(left[node], left, right);
    if(lh==-1) return -1;
    int rh = dfs(right[node], left, right);
    if(rh==-1) return -1;
    if(abs(lh-rh)>1) return -1;
    return 1 + max(lh, rh);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> left(N+1,0), right(N+1,0), isChild(N+1,0);
        for(int i=0;i<N-1;++i){
            int p,c; char dir; cin>>p>>c>>dir;
            if(dir=='L') left[p]=c; else right[p]=c;
            isChild[c]=1;
        }
        int root=1; for(int i=1;i<=N;++i) if(!isChild[i]){root=i;break;}
