import sys
sys.setrecursionlimit(200000)

def dfs(node, left, right):
    if node==0:
        return 0
    lh = dfs(left[node], left, right)
    if lh==-1:
        return -1
    rh = dfs(right[node], left, right)
    if rh==-1:
        return -1
    if abs(lh-rh)>1:
        return -1
    return 1 + max(lh, rh)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        left = [0]*(N+1)
        right = [0]*(N+1)
        is_child = [0]*(N+1)
        for __ in range(N-1):
            p = int(next(it)); c = int(next(it)); dir = next(it)
            if dir=='L':
                left[p]=c
            else:
                right[p]=c
            is_child[c]=1
        root = 1
        for i in range(1,N+1):
            if not is_child[i]:
                root=i
                break
        res = dfs(root, left, right)
        out.append('NO' if res==-1 else 'YES')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

